export function getStaticPublishedPosts(lang: "ro" | "en" | "ru" | "ua" = "ro") {
  return staticBlogPosts.filter((post) => post.published === 1 && post.lang === lang);
}

export function getStaticPostBySlug(slug: string, lang: "ro" | "en" | "ru" | "ua" = "ro") {
  return staticBlogPosts.find((post) => post.published === 1 && post.lang === lang && post.slug === slug);
}

export function getStaticBlogSlugs(lang?: "ro" | "en" | "ru" | "ua") {
  return staticBlogPosts
    .filter((post) => post.published === 1 && (!lang || post.lang === lang))
    .map((post) => post.slug);
}
